PERSISTENCIA - POST a API REST
Endpoint: http://127.0.0.1:8000/api/v1/interactions/
Campos: source=telegram, user=user_id, payload={text, message_id}
Idempotencia: X-Idempotency-Key = tg-{message_id}

parameters.functionCode:
const staticData = getWorkflowStaticData('global');
const data = $input.first().json;
const msg = (data.mensaje || '').toLowerCase().trim();
const productos = data.productos || [];

// ID unico del usuario (Telegram user_id)
const userId = String(data.user_id || data.telegram_user_id || 'anon');

// Estado persistente: modo + carrito simulado
if (!staticData[userId]) {
  staticData[userId] = { modo: 'menu', carrito: [] };
}
const userState = staticData[userId];
// El carrito "real" de la API siempre llega vacio, usamos el simulado
const carrito = userState.carrito || [];

let respuesta = '';
let accion = null;
let producto_id = null;
let producto_nombre = null;
let producto_precio = null;

// --- MENU PRINCIPAL (resetea modo a menu) ---
if (msg === '/start' || msg === 'hola' || msg === 'menu' || msg === '' || msg === 'volver') {
  userState.modo = 'menu';
  const nombre = data.first_name || 'amigo';
  respuesta = String.fromCodePoint(0x1F44B) + ' \u00A1Hola ' + nombre + '! Bienvenido al sistema de atenci\u00F3n.\n\nEleg\u00ED una opci\u00F3n:\n\n1\uFE0F\u20E3 Comprar productos\n2\uFE0F\u20E3 Ver nuestro cat\u00E1logo\n3\uFE0F\u20E3 Consultar precios\n4\uFE0F\u20E3 Hablar con un asesor\n5\uFE0F\u20E3 Otra consulta\n6\uFE0F\u20E3 Ver mi carrito\n7\uFE0F\u20E3 Finalizar compra';
}

// --- SELECCION DE PRODUCTO (solo si estamos en modo catalogo) ---
else if (userState.modo === 'catalogo' && /^\d+$/.test(msg)) {
  const num = parseInt(msg, 10) - 1;
  // Solo si el numero corresponde a un producto existente
  if (num >= 0 && num < productos.length && productos[num] && productos[num].stock > 0) {
    const p = productos[num];
    // Agregar al carrito simulado
    const existente = userState.carrito.find(item => item.id === p.id);
    if (existente) {
      existente.cantidad += 1;
    } else {
      userState.carrito = [...userState.carrito, {
        id: p.id,
        nombre: p.nombre,
        precio: p.precio,
        cantidad: 1
      }];
    }
    respuesta = String.fromCodePoint(0x2705) + ' *' + p.nombre + '* agregado a tu carrito!\n\nCantidad: ' + (existente ? existente.cantidad : 1) + '\nPrecio: $' + p.precio.toLocaleString('es-AR', {minimumFractionDigits: 2}) + '\n\nEscrib\u00ED otro n\u00FAmero para seguir agregando, o "menu" para volver.';
    accion = null; // Solo mensaje, sin API
    producto_id = p.id;
    producto_nombre = p.nombre;
    producto_precio = p.precio;
  } else if (productos[num]) {
    respuesta = String.fromCodePoint(0x274C) + ' *' + productos[num].nombre + '* no tiene stock disponible.\n\nEleg\u00ED otro producto o escrib\u00ED "menu" para volver.';
  } else {
    respuesta = String.fromCodePoint(0x274C) + ' N\u00FAmero de producto inv\u00E1lido.\n\nEscrib\u00ED "menu" para ver las opciones.';
  }
}

// --- 1: COMPRAR (catalogo numerado) ---
else if (msg === '1' || msg.includes('comprar')) {
  if (productos.length === 0) {
    respuesta = String.fromCodePoint(0x1F4ED) + ' No hay productos disponibles.\n\nEscrib\u00ED "menu" para volver.';
  } else {
    userState.modo = 'catalogo';
    carrito.length; // referencia para mantener la var en uso
    let catalogo = String.fromCodePoint(0x1F6D2) + ' *Productos para comprar*\n\nEleg\u00ED el n\u00FAmero del producto que quer\u00E9s:\n\n';
    productos.forEach((p, i) => {
      if (p.stock > 0) {
        const num = i + 1;
        const nums = [0x30, 0x31, 0x32, 0x33, 0x34, 0x35, 0x36, 0x37, 0x38, 0x39];
        const emoji = String.fromCodePoint(nums[num]) + String.fromCodePoint(0xFE0F, 0x20E3);
        const precio = '$' + p.precio.toLocaleString('es-AR', {minimumFractionDigits: 2});
        catalogo += emoji + ' *' + p.nombre + '* \u2014 ' + precio + '\n';
      }
    });
    catalogo += '\nEscrib\u00ED el n\u00FAmero del producto para agregarlo a tu carrito.\nEscrib\u00ED "menu" para volver.';
    respuesta = catalogo;
  }
}

// --- 2: CATALOGO ---
else if (msg === '2' || msg.includes('catalogo') || msg.includes('producto') || msg.includes('ver')) {
  userState.modo = 'catalogo';
  if (productos.length === 0) {
    respuesta = String.fromCodePoint(0x1F4ED) + ' No hay productos disponibles.\n\nEscrib\u00ED "menu" para volver.';
  } else {
    let catalogo = String.fromCodePoint(0x1F4CB) + ' *Nuestro Cat\u00E1logo*\n\n';
    productos.forEach(p => {
      const precio = '$' + p.precio.toLocaleString('es-AR', {minimumFractionDigits: 2});
      const stockTxt = p.stock > 0 ? String.fromCodePoint(0x2705) + ' Stock: ' + p.stock : String.fromCodePoint(0x274C) + ' Sin stock';
      catalogo += '\u2022 *' + p.nombre + '*\n  Precio: ' + precio + ' | ' + stockTxt + '\n';
      if (p.categoria) catalogo += '  Categor\u00EDa: ' + p.categoria + '\n';
      catalogo += '\n';
    });
    catalogo += '\u00BFQuer\u00E9s comprar alguno? Escrib\u00ED "1" o "comprar".\n\nEscrib\u00ED "menu" para volver.';
    respuesta = catalogo;
  }
}

// --- 3: PRECIOS ---
else if (msg === '3' || msg.includes('precio')) {
  if (productos.length === 0) {
    respuesta = String.fromCodePoint(0x1F4ED) + ' No hay productos disponibles.\n\nEscrib\u00ED "menu" para volver.';
  } else {
    let precios = String.fromCodePoint(0x1F4B0) + ' *Lista de Precios*\n\n';
    productos.forEach(p => {
      const precio = '$' + p.precio.toLocaleString('es-AR', {minimumFractionDigits: 2});
      precios += '\u2022 *' + p.nombre + '*: ' + precio + '\n';
    });
    respuesta = precios + '\nEscrib\u00ED "menu" para volver.';
  }
}

// --- 4: ASESOR ---
else if (msg === '4' || msg.includes('asesor') || msg.includes('hablar')) {
  respuesta = 'Gracias por tu consulta. Un asesor se va a comunicar con vos a la brevedad.\n\nEscrib\u00ED "menu" para volver.';
}

// --- 5: OTRA CONSULTA ---
else if (msg === '5' || msg.includes('consulta') || msg.includes('otra')) {
  respuesta = 'Contame tu consulta y te respondemos a la brevedad.\n\nEscrib\u00ED "menu" para volver.';
}

// --- 6: VER CARRITO (usa carrito simulado) ---
else if (msg === '6' || msg.includes('carrito') || msg.includes('mis productos')) {
  if (userState.carrito.length === 0) {
    respuesta = String.fromCodePoint(0x1F6D2) + ' *Tu carrito est\u00E1 vac\u00EDo*\n\nMir\u00E1 nuestro cat\u00E1logo (opci\u00F3n 2) y eleg\u00ED productos para comprar.\n\nEscrib\u00ED "menu" para volver.';
  } else {
    let txt = String.fromCodePoint(0x1F6D2) + ' *Tu Carrito*\n\n';
    let total = 0;
    userState.carrito.forEach(p => {
      const subtotal = p.precio * p.cantidad;
      total += subtotal;
      txt += '\u2022 *' + p.nombre + '*\n  $' + p.precio.toLocaleString('es-AR', {minimumFractionDigits: 2}) + ' x ' + p.cantidad + ' = $' + subtotal.toLocaleString('es-AR', {minimumFractionDigits: 2}) + '\n';
    });
    txt += '\n*Total: $' + total.toLocaleString('es-AR', {minimumFractionDigits: 2}) + '*';
    txt += '\n\nPara finalizar tu compra, escrib\u00ED "7" o "finalizar".\nEscrib\u00ED "menu" para volver.';
    respuesta = txt;
  }
}

// --- 7: FINALIZAR COMPRA ---
else if (msg === '7' || msg.includes('finalizar') || msg.includes('terminar')) {
    respuesta = String.fromCodePoint(0x2705) + ' *\u00A1Compra finalizada con \u00E9xito!*\n\nGracias por tu compra. En breve nos pondremos en contacto para coordinar la entrega.\n\nEscrib\u00ED "menu" para volver.';
    accion = 'finalizar';}

// --- DEFAULT ---
else {
    respuesta = 'No entendí ese comando. Escribí "menu" para ver las opciones disponibles.';
}

// Persistir estado del carrito simulado
staticData[userId] = JSON.parse(JSON.stringify(userState));

// Salida
return [
  {
    json: {
      mensaje: respuesta,
      accion: accion,
      producto_id: producto_id,
      producto_nombre: producto_nombre,
      producto_precio: producto_precio
    }
  }
];

const editFieldsData = $node["Edit Fields"].json;
const productsResponse = $input.first().json;
const createClientData = $node["Create Client"].json;

const productos = productsResponse.items || [];
let carrito = [];

return [{
  json: {
    ...editFieldsData,
    productos: productos,
    carrito: carrito,
    cliente_id: createClientData ? createClientData.id : null
  }
}];
